 * Merge overlapping intervals.
 *
 * @param {Array<[number, number]>} list - Array of `[start, end]` intervals.
 * @returns {Array<[number, number]>} New array of merged, non-overlapping
 *   intervals sorted by start. Adjacent/touching intervals (e.g. [1,2],[2,3])
 *   are merged.
 * @throws {TypeError} If input is not an array of valid two-element numeric
 *   intervals with finite `start <= end`.
 */
export function mergeIntervals(list) {
  if (!Array.isArray(list)) {
    throw new TypeError("mergeIntervals: expected an array of intervals");
  }

  // Validate every interval at the boundary before doing any work.
  for (let i = 0; i < list.length; i++) {
    const iv = list[i];
    if (!Array.isArray(iv) || iv.length !== 2) {
      throw new TypeError(
        `mergeIntervals: interval at index ${i} must be a two-element array`
      );
    }
    const [start, end] = iv;
    if (
      typeof start !== "number" ||
      typeof end !== "number" ||
      !Number.isFinite(start) ||
      !Number.isFinite(end)
    ) {
      throw new TypeError(
        `mergeIntervals: interval at index ${i} must contain two finite numbers`
      );
    }
    if (start > end) {
      throw new TypeError(
        `mergeIntervals: interval at index ${i} has start (${start}) > end (${end})`
      );
    }
  }

  if (list.length === 0) return [];

  // Sort by start (then end) on a copy so the caller's array is untouched.
  const sorted = list.map((iv) => [iv[0], iv[1]]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);

  const merged = [sorted[0]];
  for (let i = 1; i < sorted.length; i++) {
    const [start, end] = sorted[i];
    const last = merged[merged.length - 1];
    if (start <= last[1]) {
      // Overlapping or touching: extend the current interval.
      last[1] = Math.max(last[1], end);
    } else {
      merged.push([start, end]);
    }
  }

  return merged;
}
